import { component$, Slot } from "@builder.io/qwik";
import { Link } from "@builder.io/qwik-city";

export default component$(() => {
  return (
    <>
      <header class="site-header">
        <nav>
          <Link href="/notes" class="brand">
            📝 Markdown Notes
          </Link>
        </nav>
      </header>
      <main class="site-main">
        <Slot />
      </main>
      <footer class="site-footer">
        <small>Stored locally in SQLite · rendered with marked + sanitize-html</small>
      </footer>
    </>
  );
});

import { component$ } from "@builder.io/qwik";
import { Link, type DocumentHead } from "@builder.io/qwik-city";

export default component$(() => {
  return (
    <section class="hero">
      <h1>Markdown Notes</h1>
      <p>
        A tiny notes app built with <strong>Qwik City</strong> and a local
        SQLite database. Notes are written in Markdown and rendered as
        sanitized HTML on the server.
      </p>
      <p>
        <Link href="/notes" class="button primary">
          Go to my notes →
        </Link>
      </p>
    </section>
  );
});

export const head: DocumentHead = {
  title: "Markdown Notes",
  meta: [
    {
      name: "description",
      content: "A local-first Markdown notes manager built with Qwik City.",
    },
  ],
};

import { component$ } from "@builder.io/qwik";
import {
  Form,
  Link,
  routeAction$,
  routeLoader$,
  zod$,
  z,
  type DocumentHead,
} from "@builder.io/qwik-city";
import { createNote, deleteNote, listNotes } from "~/lib/db";

/**
 * Server-side loader: read all notes from SQLite.
 *
 * Because `routeLoader$` is a server-only boundary, the
 * `better-sqlite3` import inside `~/lib/db` never leaks into the client
 * bundle.
 */
export const useNotesLoader = routeLoader$(() => {
  return {
    notes: listNotes(),
  };
});

/**
 * Server-side action: create a new note.
 *
 * `zod$` validates the form payload on the server. Empty titles / empty
 * content are rejected before anything is written.
 */
export const useCreateNoteAction = routeAction$(
  async (data) => {
    const note = createNote({
      title: data.title,
      content: data.content,
    });
    return { success: true as const, id: note.id };
  },
  zod$({
    title: z
      .string()
      .trim()
      .min(1, "Title is required")
      .max(200, "Title is too long"),
    content: z
      .string()
      .min(1, "Content is required"),
  }),
);

/**
 * Server-side action: delete a note by id.
 */
export const useDeleteNoteAction = routeAction$(
  async (data) => {
    const removed = deleteNote(data.id);
    return { success: removed };
  },
  zod$({
    id: z.coerce.number().int().positive(),
  }),
);

export default component$(() => {
  const notesSig = useNotesLoader();
  const createAction = useCreateNoteAction();
  const deleteAction = useDeleteNoteAction();

  const createFieldErrors = createAction.value?.failed ? createAction.value.fieldErrors : undefined;
  const createFormError = createAction.value?.failed
    ? (createAction.value as any).formErrors?.[0]
    : undefined;

  return (
    <section class="notes-page">
      <h1>My Notes</h1>

      <div class="create-card">
        <h2>New note</h2>
        <Form action={createAction} class="create-form">
          <label>
            <span>Title</span>
            <input
              type="text"
              name="title"
              placeholder="Note title"
              value={createAction.formData?.get("title")?.toString() ?? ""}
              required
            />
            {createFieldErrors?.title && (
              <small class="error">{createFieldErrors.title[0]}</small>
            )}
          </label>
          <label>
            <span>Markdown content</span>
            <textarea
              name="content"
              rows={6}
              placeholder="# Hello&#10;Write **Markdown** here…"
              required
            >
              {createAction.formData?.get("content")?.toString() ?? ""}
            </textarea>
            {createFieldErrors?.content && (
              <small class="error">{createFieldErrors.content[0]}</small>
            )}
          </label>
          {createFormError && <p class="error">{createFormError}</p>}
          <button type="submit" class="button primary" disabled={createAction.isRunning}>
            {createAction.isRunning ? "Creating…" : "Create note"}
          </button>
        </Form>
      </div>

      <h2>All notes</h2>
      {notesSig.value.notes.length === 0 ? (
        <p class="empty">No notes yet — create your first one above.</p>
      ) : (
        <ul class="notes-list">
          {notesSig.value.notes.map((note) => (
            <li key={note.id} class="note-item">
              <div class="note-meta">
                <Link href={`/notes/${note.id}`} class="note-title">
                  {note.title}
                </Link>
                <small class="note-dates">
                  updated {note.updated_at}
                </small>
              </div>
              <div class="note-actions">
                <Link href={`/notes/${note.id}/edit`} class="button">
                  Edit
                </Link>
                <Form action={deleteAction} class="inline-form">
                  <input type="hidden" name="id" value={note.id} />
                  <button
                    type="submit"
                    class="button danger"
                    onClick$={(event) => {
                      if (
                        !confirm(
                          `Delete note "${note.title}"? This cannot be undone.`,
                        )
                      ) {
                        event.preventDefault();
                      }
                    }}
                  >
                    Delete
                  </button>
                </Form>
              </div>
            </li>
          ))}
        </ul>
      )}
    </section>
  );
});

export const head: DocumentHead = {
  title: "Notes · Markdown Notes",
  meta: [
    {
      name: "description",
      content: "Browse, create and delete your local Markdown notes.",
    },
  ],
};

