import { component$ } from "@builder.io/qwik";
import {
  Link,
  routeLoader$,
  type DocumentHead,
} from "@builder.io/qwik-city";
import { getNote } from "~/lib/db";
import { renderMarkdown } from "~/lib/markdown";

/**
 * Server-side loader: fetch a single note by id and convert its
 * Markdown content to sanitized HTML. Returns 404 if the note does
 * not exist.
 */
export const useNoteLoader = routeLoader$(async (event) => {
  const id = Number(event.params.id);
  if (!Number.isFinite(id) || id <= 0 || !Number.isInteger(id)) {
    throw event.error(404, "Note not found");
  }
  const note = getNote(id);
  if (!note) {
    throw event.error(404, "Note not found");
  }
  return {
    id: note.id,
    title: note.title,
    createdAt: note.created_at,
    updatedAt: note.updated_at,
    html: renderMarkdown(note.content),
  };
});

export default component$(() => {
  const noteSig = useNoteLoader();
  const note = noteSig.value;

  return (
    <article class="note-detail">
      <p class="back-link">
        <Link href="/notes">← All notes</Link>
      </p>
      <h1>{note.title}</h1>
      <p class="note-dates">
        <small>
          Created {note.createdAt} · last updated {note.updatedAt}
        </small>
      </p>
      <div class="note-actions">
        <Link href={`/notes/${note.id}/edit`} class="button">
          Edit
        </Link>
      </div>
      <div class="note-content" dangerouslySetInnerHTML={note.html} />
    </article>
  );
});

export const head: DocumentHead = ({ resolveValue }) => {
  const note = resolveValue(useNoteLoader);
  return {
    title: `${note.title} · Markdown Notes`,
    meta: [
      {
        name: "description",
        content: `Read the note "${note.title}".`,
      },
    ],
  };
};

import { component$ } from "@builder.io/qwik";
import {
  Form,
  Link,
  routeAction$,
  routeLoader$,
  zod$,
  z,
  type DocumentHead,
} from "@builder.io/qwik-city";
import { getNote, updateNote } from "~/lib/db";

/**
 * Server-side loader: fetch the note being edited so the form can be
 * pre-filled. Returns 404 if the id is unknown.
 */
export const useEditLoader = routeLoader$(async (event) => {
  const id = Number(event.params.id);
  if (!Number.isFinite(id) || id <= 0 || !Number.isInteger(id)) {
    throw event.error(404, "Note not found");
  }
  const note = getNote(id);
  if (!note) {
    throw event.error(404, "Note not found");
  }
  return {
    id: note.id,
    title: note.title,
    content: note.content,
  };
});

/**
 * Server-side action: update the note. Validates the input with
 * `zod$` and writes through the SQLite helper. If the note has
 * vanished between the GET and the POST, return 404.
 */
export const useUpdateNoteAction = routeAction$(
  async (data, event) => {
    const id = Number(event.params.id);
    if (!Number.isFinite(id) || id <= 0 || !Number.isInteger(id)) {
      throw event.error(404, "Note not found");
    }
    const updated = updateNote(id, {
      title: data.title,
      content: data.content,
    });
    if (!updated) {
      throw event.error(404, "Note not found");
    }
    return { success: true as const };
  },
  zod$({
    title: z
      .string()
      .trim()
      .min(1, "Title is required")
      .max(200, "Title is too long"),
    content: z.string().min(1, "Content is required"),
  }),
);

function firstError(value: unknown): string | undefined {
  if (Array.isArray(value)) {
    return value[0];
  }
  if (typeof value === "string") {
    return value;
  }
  return undefined;
}

export default component$(() => {
  const editSig = useEditLoader();
  const updateAction = useUpdateNoteAction();
  const note = editSig.value;

  const isFailed = updateAction.value?.failed === true;
  const fieldErrors = isFailed
    ? (updateAction.value as { fieldErrors?: Record<string, unknown> })
        .fieldErrors
    : undefined;
  const formErrors = isFailed
    ? (updateAction.value as { formErrors?: string[] }).formErrors
    : undefined;

  // Pre-fill from the loader, but if the user already submitted the
  // form and it failed, keep whatever they typed instead.
  const submittedTitle =
    updateAction.formData?.get("title")?.toString() ?? note.title;
  const submittedContent =
    updateAction.formData?.get("content")?.toString() ?? note.content;

  return (
    <section class="note-edit">
      <p class="back-link">
        <Link href={`/notes/${note.id}`}>← Back to note</Link>
      </p>
      <h1>Edit note</h1>

      <Form action={updateAction} class="edit-form">
        <label>
          <span>Title</span>
          <input
            type="text"
            name="title"
            value={submittedTitle}
            required
          />
          {firstError(fieldErrors?.title) && (
            <small class="error">{firstError(fieldErrors?.title)}</small>
          )}
        </label>
        <label>
          <span>Markdown content</span>
          <textarea name="content" rows={14} required>
            {submittedContent}
          </textarea>
          {firstError(fieldErrors?.content) && (
            <small class="error">{firstError(fieldErrors?.content)}</small>
          )}
        </label>
        {formErrors && formErrors.length > 0 && (
          <p class="error">{formErrors[0]}</p>
        )}
        <div class="form-actions">
          <button
            type="submit"
            class="button primary"
            disabled={updateAction.isRunning}
          >
            {updateAction.isRunning ? "Saving…" : "Save changes"}
          </button>
          <Link href={`/notes/${note.id}`} class="button">
            Cancel
          </Link>
        </div>
      </Form>
    </section>
  );
});

export const head: DocumentHead = ({ resolveValue }) => {
  const note = resolveValue(useEditLoader);
  return {
    title: `Edit "${note.title}" · Markdown Notes`,
  };
};

/* -----------------------------------------------------------------------
   Markdown Notes — global styles
----------------------------------------------------------------------- */

:root {
  --bg: #f6f7fb;
  --fg: #1f2933;
  --muted: #52606d;
  --border: #e4e7eb;
  --card: #ffffff;
  --accent: #2f6feb;
  --accent-fg: #ffffff;
  --danger: #c0392b;
  --danger-fg: #ffffff;
  --error: #b3261e;
  --error-bg: #fdecea;
  --code-bg: #f1f3f5;
  --shadow: 0 1px 2px rgba(0, 0, 0, 0.04), 0 4px 12px rgba(0, 0, 0, 0.04);
  font-family: ui-sans-serif, system-ui, -apple-system, "Segoe UI", Roboto,
    "Helvetica Neue", Arial, sans-serif;
  color-scheme: light;
}

* {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
  background: var(--bg);
  color: var(--fg);
  line-height: 1.55;
  min-height: 100%;
}

body {
  display: flex;
  flex-direction: column;
  min-height: 100vh;
}

a {
  color: var(--accent);
  text-decoration: none;
}

a:hover,
a:focus {
  text-decoration: underline;
}

.site-header {
  background: var(--card);
  border-bottom: 1px solid var(--border);
  padding: 0.85rem 1.25rem;
}

.site-header nav {
  max-width: 880px;
  margin: 0 auto;
}

.site-header .brand {
  font-weight: 700;
  font-size: 1.1rem;
  color: var(--fg);
}

.site-main {
  flex: 1;
  width: 100%;
  max-width: 880px;
  margin: 0 auto;
  padding: 1.5rem 1.25rem 3rem;
}

.site-footer {
  text-align: center;
  color: var(--muted);
  padding: 1rem;
  border-top: 1px solid var(--border);
  background: var(--card);
}

/* -----------------------------------------------------------------------
   Hero / landing page
----------------------------------------------------------------------- */

.hero h1 {
  font-size: 2.25rem;
  margin: 0 0 0.5rem;
}

.hero p {
  color: var(--muted);
}

/* -----------------------------------------------------------------------
   Forms
----------------------------------------------------------------------- */

form {
  display: flex;
  flex-direction: column;
  gap: 0.85rem;
}

label {
  display: flex;
  flex-direction: column;
  gap: 0.35rem;
  font-size: 0.95rem;
  color: var(--muted);
}

label span {
  font-weight: 600;
  color: var(--fg);
}

input[type="text"],
textarea {
  font: inherit;
  width: 100%;
  padding: 0.6rem 0.75rem;
  border: 1px solid var(--border);
  border-radius: 6px;
  background: var(--card);
  color: var(--fg);
  resize: vertical;
}

input[type="text"]:focus,
textarea:focus {
  outline: 2px solid var(--accent);
  outline-offset: 1px;
  border-color: transparent;
}

textarea {
  font-family: ui-monospace, SFMono-Regular, Menlo, Consolas, monospace;
  font-size: 0.92rem;
  line-height: 1.5;
}

.button {
  display: inline-flex;
  align-items: center;
  justify-content: center;
  gap: 0.35rem;
  padding: 0.5rem 0.9rem;
  border: 1px solid var(--border);
  border-radius: 6px;
  background: var(--card);
  color: var(--fg);
  cursor: pointer;
  font: inherit;
  font-size: 0.92rem;
  text-decoration: none;
}

.button:hover,
.button:focus {
  border-color: var(--accent);
  text-decoration: none;
}

.button.primary {
  background: var(--accent);
  color: var(--accent-fg);
  border-color: var(--accent);
}

.button.primary:hover,
.button.primary:focus {
  filter: brightness(0.95);
}

.button.danger {
  background: var(--danger);
  color: var(--danger-fg);
  border-color: var(--danger);
}

.button.danger:hover,
.button.danger:focus {
  filter: brightness(0.95);
}

.button[disabled] {
  opacity: 0.6;
  cursor: progress;
}

.form-actions {
  display: flex;
  gap: 0.5rem;
  flex-wrap: wrap;
}

.error {
  color: var(--error);
  background: var(--error-bg);
  border-radius: 4px;
  padding: 0.25rem 0.5rem;
  font-size: 0.85rem;
}

/* -----------------------------------------------------------------------
   Notes index page
----------------------------------------------------------------------- */

.notes-page h1 {
  margin-top: 0;
}

.create-card {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 1.25rem;
  box-shadow: var(--shadow);
  margin-bottom: 1.5rem;
}

.create-card h2 {
  margin-top: 0;
  font-size: 1.1rem;
}

.create-form {
  margin-top: 0.5rem;
}

.notes-list {
  list-style: none;
  padding: 0;
  margin: 0;
  display: flex;
  flex-direction: column;
  gap: 0.5rem;
}

.note-item {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 1rem;
  padding: 0.85rem 1rem;
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 8px;
  box-shadow: var(--shadow);
}

.note-meta {
  display: flex;
  flex-direction: column;
  gap: 0.15rem;
  min-width: 0;
}

.note-title {
  font-weight: 600;
  color: var(--fg);
  font-size: 1.02rem;
  word-break: break-word;
}

.note-dates {
  color: var(--muted);
  font-size: 0.82rem;
}

.note-actions {
  display: flex;
  gap: 0.4rem;
  flex-shrink: 0;
}

.inline-form {
  margin: 0;
  display: inline;
}

.empty {
  color: var(--muted);
  font-style: italic;
}

.back-link {
  margin: 0 0 0.75rem;
}

/* -----------------------------------------------------------------------
   Note detail
----------------------------------------------------------------------- */

.note-detail h1 {
  margin-top: 0.25rem;
  margin-bottom: 0.25rem;
}

.note-content {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 1.25rem 1.5rem;
  box-shadow: var(--shadow);
  margin-top: 1rem;
}

.note-content h1,
.note-content h2,
.note-content h3 {
  margin-top: 1.2em;
}

.note-content pre {
  background: var(--code-bg);
  padding: 0.75rem;
  border-radius: 6px;
  overflow-x: auto;
}

.note-content code {
  background: var(--code-bg);
  padding: 0.1rem 0.3rem;
  border-radius: 4px;
  font-size: 0.9em;
}

.note-content pre code {
  background: transparent;
  padding: 0;
}

.note-content blockquote {
  border-left: 4px solid var(--accent);
  margin: 0;
  padding: 0.25rem 1rem;
  color: var(--muted);
  background: rgba(47, 111, 235, 0.05);
}

.note-content table {
  border-collapse: collapse;
}

.note-content th,
.note-content td {
  border: 1px solid var(--border);
  padding: 0.4rem 0.6rem;
}

/* -----------------------------------------------------------------------
   Note edit
----------------------------------------------------------------------- */

.note-edit h1 {
  margin-top: 0.25rem;
}

.edit-form {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 10px;
  padding: 1.25rem;
  box-shadow: var(--shadow);
}

